#!/usr/bin/env bash
# SymbiYosys BMC on emitted SV (optional; requires sby + yosys).
set -euo pipefail
ROOT="$(cd "$(dirname "$0")/.." && pwd)"
cd "$ROOT"

if [[ "${GNOSIS_RTL_FORMAL:-}" != "1" ]]; then
  echo "rtl-formal-symbiyosys: skip (set GNOSIS_RTL_FORMAL=1 to run)"
  exit 0
fi

if ! command -v sby >/dev/null 2>&1; then
  echo "rtl-formal-symbiyosys: sby not in PATH; skipping"
  exit 0
fi

cargo run --quiet --manifest-path "$ROOT/rtl-bridge/Cargo.toml" --bin gnosis-rtl-emit
mkdir -p "$ROOT/verifylog/formal"
cd "$ROOT/rtl-bridge/formal"
sby -f sieve_fsm.sby
cp -f "$ROOT/rtl-bridge/formal/sieve_fsm/logfile.txt" "$ROOT/verifylog/formal/sieve_fsm-logfile.txt" 2>/dev/null || true
echo "rtl-formal-symbiyosys: done (artifacts under rtl-bridge/formal/sieve_fsm/)"
